"use client";

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useRouter } from 'next/navigation';
import {
  Plus, Trash2, Edit3, MessageSquare,
  Send, Image as ImageIcon, X, Save, CheckCircle2, LogOut, Loader2
} from 'lucide-react';
import { useProjectStore } from '../../store/useProjectStore';

export default function Admin() {
  const router = useRouter();

  const {
    projects, addProject, deleteProject,
    messages, deleteMessage, logout, fetchData, isLoading
  } = useProjectStore() as any;

  const [isReady, setIsReady] = useState(false);
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [previewImages, setPreviewImages] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const formRef = useRef<HTMLFormElement>(null);

  useEffect(() => {
    fetchData();
    setIsReady(true);
  }, [fetchData]);

  const handleLogout = () => {
    logout();
    router.push('/');
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const img = new window.Image();
          img.src = reader.result as string;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            const MAX_WIDTH = 1200;
            const scaleSize = MAX_WIDTH / img.width;
            canvas.width = MAX_WIDTH;
            canvas.height = img.height * scaleSize;
            const ctx = canvas.getContext('2d');
            if (ctx) {
              ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
              const highQualBase64 = canvas.toDataURL('image/jpeg', 0.7);
              setPreviewImages(prev => [...prev, highQualBase64]);
            }
          };
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const handleFormSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const projectData = {
      title: formData.get('title') as string,
      client: formData.get('client') as string,
      type: formData.get('type') as string, // ✅ Maintenant récupéré via le select
      description: formData.get('description') as string,
      images: previewImages,
      stars: 0,
    };

    const success = await addProject(projectData);

    if (success) {
      setPreviewImages([]);
      e.currentTarget.reset();
    }
  };

  if (!isReady) return null;

  return (
    <div className="min-h-screen bg-[#F8F9FA] p-4 md:p-10 font-sans text-[#1A1A1A]">
      <div className="max-w-7xl mx-auto">

        {/* HEADER TIGER */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6 border-b-2 border-gray-100 pb-8">
          <div>
            <h1 className="text-4xl font-black uppercase tracking-tighter">
              Console <span className="text-[#FFB800]">Ingénieur</span>
            </h1>
            <p className="text-gray-500 font-medium flex items-center gap-2 italic">
              {isLoading ? <Loader2 size={16} className="animate-spin text-[#FFB800]" /> : <CheckCircle2 size={16} className="text-green-500" />}
              Tiger Construction • Localhost 192.168.1.116
            </p>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
             <div className="bg-white px-6 py-3 shadow-sm border rounded-sm flex-1 md:flex-none">
                <p className="text-[10px] font-black uppercase text-gray-400">Projets</p>
                <p className="text-xl font-black">{projects?.length || 0}</p>
             </div>
             <button onClick={handleLogout} className="bg-red-50 text-red-600 border-2 border-red-100 px-6 py-3 rounded-sm font-black text-[10px] uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all flex items-center gap-2">
               <LogOut size={16} /> Déconnexion
             </button>
          </div>
        </div>

        <div className="grid lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-8">
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white p-8 shadow-2xl border-t-8 border-[#1A1A1A]">
              <h2 className="text-xl font-black mb-8 flex items-center gap-3 uppercase">
                <Plus className="text-[#FFB800]" /> Publier un nouvel ouvrage
              </h2>

              <form ref={formRef} onSubmit={handleFormSubmit} className="grid md:grid-cols-2 gap-8">
                <div className="space-y-5">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-gray-400">Désignation</label>
                    <input name="title" required type="text" placeholder="ex: Pont sur le Wouri" className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-[#FFB800] outline-none font-bold" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-gray-400">Maître d'Ouvrage</label>
                    <input name="client" required type="text" placeholder="ex: MINTP" className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-[#FFB800] outline-none" />
                  </div>
                  {/* ✅ NOUVEAU : Champ Type (Indispensable pour Prisma) */}
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-gray-400">Spécification Technique</label>
                    <select name="type" required className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-[#FFB800] outline-none font-bold appearance-none">
                      <option value="Génie Civil">Génie Civil</option>
                      <option value="Bâtiment">Bâtiment / Immeuble</option>
                      <option value="Route">Infrastructure Routière</option>
                      <option value="Hydraulique">Ouvrage Hydraulique</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-5">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-gray-400">Description des Travaux</label>
                    <textarea name="description" placeholder="Détails du chantier..." className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-[#FFB800] outline-none h-32 resize-none" />
                  </div>

                  {/* Zone Upload & Previews */}
                  <div className="space-y-3">
                    <div className="border-2 border-dashed border-gray-200 p-6 text-center cursor-pointer hover:border-[#FFB800] transition-colors" onClick={() => fileInputRef.current?.click()}>
                      <input type="file" multiple hidden ref={fileInputRef} onChange={handleImageUpload} accept="image/*" />
                      <ImageIcon className="mx-auto text-gray-300 mb-2" size={32} />
                      <span className="text-[10px] font-black text-gray-400 block uppercase">Charger Photos</span>
                    </div>

                    {/* Previews des images en cours d'upload */}
                    <div className="flex gap-2 overflow-x-auto pb-2">
                      {previewImages.map((img, idx) => (
                        <div key={idx} className="relative w-16 h-16 flex-shrink-0 border">
                          <img src={img} className="w-full h-full object-cover" />
                          <button type="button" onClick={() => setPreviewImages(prev => prev.filter((_, i) => i !== idx))} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5">
                            <X size={10} />
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <button type="submit" disabled={isLoading} className="md:col-span-2 bg-[#1A1A1A] text-white py-5 font-black uppercase tracking-[0.3em] hover:bg-[#FFB800] hover:text-black transition-all flex items-center justify-center gap-4 disabled:opacity-50">
                  {isLoading ? <Loader2 className="animate-spin" /> : <><CheckCircle2 size={20}/> Valider le Dossier</>}
                </button>
              </form>
            </motion.div>

            {/* LISTE MINIATURES */}
            <div className="grid md:grid-cols-2 gap-4">
              {projects?.map((p: any) => (
                <div key={p.id} className="bg-white p-4 border-l-4 border-gray-200 flex justify-between items-center group hover:border-[#FFB800] transition-all shadow-sm">
                   <div className="flex items-center gap-3 overflow-hidden">
                      <div className="w-12 h-12 bg-gray-100 overflow-hidden flex-shrink-0">
                        {p.images?.[0] && <img src={p.images[0]} alt="" className="w-full h-full object-cover" />}
                      </div>
                      <div className="overflow-hidden">
                        <h4 className="font-black uppercase text-[10px] truncate">{p.title}</h4>
                        <p className="text-[8px] text-gray-400 uppercase font-bold">{p.type}</p>
                      </div>
                   </div>
                   <button onClick={() => deleteProject(p.id)} className="p-2 text-gray-300 hover:text-red-600 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
          </div>

          {/* HUB MESSAGES */}
          <div className="space-y-6">
            <h2 className="text-xl font-black flex items-center gap-3 uppercase">
              <MessageSquare className="text-[#FFB800]" /> Demandes Clients
              <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full">{messages?.length || 0}</span>
            </h2>
            <div className="space-y-4 max-h-[800px] overflow-y-auto pr-2">
              {messages?.map((msg: any) => (
                <motion.div key={msg.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="bg-white p-6 shadow-xl border-t-4 border-[#FFB800]">
                  <div className="flex justify-between items-start mb-2">
                    <h4 className="font-black text-lg leading-tight">{msg.name}</h4>
                    <button onClick={() => deleteMessage(msg.id)} className="text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={16} /></button>
                  </div>
                  <p className="text-[10px] font-black text-gray-400 uppercase border-b pb-2 mb-4">{msg.subject}</p>
                  <p className="text-sm italic text-gray-600 mb-6 bg-gray-50 p-3 rounded-sm">"{msg.content}"</p>
                  <a href={`https://wa.me/237${msg.whatsapp?.replace(/\s/g, '')}`} target="_blank" rel="noreferrer" className="flex items-center justify-center gap-3 w-full bg-[#25D366] text-white py-3 font-black text-[10px] uppercase tracking-widest hover:bg-[#128C7E] transition-all shadow-md">
                    <Send size={14} /> WhatsApp Direct
                  </a>
                </motion.div>
              ))}
              {messages?.length === 0 && <p className="text-center py-10 text-gray-400 font-bold uppercase text-[10px] tracking-widest border-2 border-dashed">Aucun message</p>}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}